<div class="modal fade finance-ui-modal" id="printerDeviceModal" tabindex="-1" aria-hidden="true"><div class="modal-dialog modal-xl modal-dialog-scrollable"><div class="modal-content"><div class="modal-header"><div><h5 class="modal-title" id="printerDeviceModalLabel">Tambah Device Printer</h5><div class="small text-muted">Data device fisik printer desktop. Gunakan <strong>LOCAL_AGENT</strong> untuk printer bluetooth yang dicetak lewat Python helper.</div></div><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><form id="device-form" class="row g-3"><input type="hidden" name="id" value=""><div class="col-md-3"><label class="form-label mb-1 small text-muted">Kode</label><input class="form-control" name="device_code" placeholder="Otomatis saat simpan"></div><div class="col-md-5"><label class="form-label mb-1 small text-muted">Nama Device</label><input class="form-control" name="device_name" required></div><div class="col-md-4"><label class="form-label mb-1 small text-muted">Outlet</label><select class="form-select" name="outlet_id"><option value="">Semua / Global</option><?php foreach ($outlets as $outlet): ?><option value="<?php echo (int)$outlet['id']; ?>"><?php echo html_escape((string)$outlet['outlet_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label class="form-label mb-1 small text-muted">Printer Role</label><select class="form-select" name="printer_role"><option value="KASIR">KASIR</option><option value="BAR">BAR</option><option value="KITCHEN">KITCHEN</option><option value="CHECKER">CHECKER</option><option value="CUSTOM">CUSTOM</option></select></div><div class="col-md-3"><label class="form-label mb-1 small text-muted">Print Scope</label><select class="form-select" name="print_scope"><option value="DIVISION">DIVISION</option><option value="ALL">ALL</option></select></div><div class="col-md-3"><label class="form-label mb-1 small text-muted">Connection</label><select class="form-select" name="connection_type"><option value="LOCAL_AGENT">LOCAL_AGENT</option><option value="USB">USB</option><option value="LAN">LAN</option></select></div><div class="col-md-3"><label class="form-label mb-1 small text-muted">Agent OS</label><select class="form-select" name="agent_os"><option value="WINDOWS">WINDOWS</option><option value="UBUNTU">UBUNTU</option><option value="OTHER">OTHER</option></select></div><div class="col-md-4"><label class="form-label mb-1 small text-muted">Agent Host</label><input class="form-control" name="agent_host" placeholder="POS-PRINTER-AGENT-01"></div><div class="col-md-4"><label class="form-label mb-1 small text-muted">Nama Device OS</label><input class="form-control" name="system_device_name" placeholder="EPSON-TM-M30"></div><div class="col-md-4"><label class="form-label mb-1 small text-muted">MAC Address</label><input class="form-control font-monospace" name="mac_address" placeholder="86677A7B9914"></div><div class="col-md-4"><label class="form-label mb-1 small text-muted">IP Address</label><input class="form-control" name="ip_address" placeholder="192.168.1.25"></div><div class="col-md-2"><label class="form-label mb-1 small text-muted">Port</label><input type="number" class="form-control" name="port" min="0" max="65535"></div><div class="col-md-2"><label class="form-label mb-1 small text-muted">Python Port</label><input type="number" class="form-control" name="python_port" min="1" max="65535" placeholder="3000"></div><div class="col-md-2"><label class="form-label mb-1 small text-muted">Paper (mm)</label><select class="form-select" name="paper_width_mm"><option value="80">80</option><option value="58">58</option></select></div><div class="col-md-2"><label class="form-label mb-1 small text-muted">Status</label><select class="form-select" name="is_active"><option value="1">Aktif</option><option value="0">Nonaktif</option></select></div></form></div><div class="modal-footer"><button type="button" class="btn btn-light" data-bs-dismiss="modal">Batal</button><button type="button" class="btn btn-primary" id="btn-save-device">Simpan Device</button></div></div></div></div>
<script>
document.addEventListener('DOMContentLoaded', function () {
  const initialDeviceFilters = <?php echo json_encode($deviceFilters, JSON_INVALID_UTF8_SUBSTITUTE); ?>;
  const deviceState = { q: initialDeviceFilters.q || '', status: initialDeviceFilters.status || 'ACTIVE', outlet_id: parseInt(initialDeviceFilters.outlet_id || 0, 10) || 0, page: parseInt(initialDeviceFilters.page || 1, 10), limit: parseInt(initialDeviceFilters.limit || 10, 10) || 10 };
  const deviceModal = new bootstrap.Modal(document.getElementById('printerDeviceModal')); const deviceForm = document.getElementById('device-form');
  function escapeHtml(v) { return String(v ?? '').replace(/[&<>\"']/g, (m) => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',"'":'&#039;'}[m])); }
  function statusBadge(flag) { return Number(flag || 0) === 1 ? '<span class="badge bg-success-subtle text-success-emphasis">Aktif</span>' : '<span class="badge bg-danger-subtle text-danger-emphasis">Nonaktif</span>'; }
  async function getJson(url) { const r = await fetch(url, { headers: { 'X-Requested-With': 'XMLHttpRequest' } }); const t = await r.text(); let j = null; try { j = JSON.parse(t); } catch (e) { const snippet = String(t || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 220); throw new Error(snippet ? `Response backend tidak valid: ${snippet}` : 'Response backend tidak valid dan bukan JSON.'); } if (!r.ok || !j.ok) throw new Error(j.message || 'Gagal memuat data'); return j; }
  async function postJson(url, payload) { const r = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-Requested-With': 'XMLHttpRequest' }, body: JSON.stringify(payload) }); const t = await r.text(); let j = null; try { j = JSON.parse(t); } catch (e) { const snippet = String(t || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 220); throw new Error(snippet ? `Response save backend tidak valid: ${snippet}` : 'Response save backend tidak valid dan bukan JSON.'); } if (!r.ok || !j.ok) throw new Error(j.message || 'Gagal menyimpan data'); return j; }
  function rowPayload(row) { return encodeURIComponent(JSON.stringify(row || {})); }
  function parseRow(payload) { return JSON.parse(decodeURIComponent(payload)); }
  function pager(meta) { const total=Number(meta.total||0), page=Number(meta.page||1), totalPages=Number(meta.total_pages||1), limit=Number(meta.limit||deviceState.limit||10); const start=total===0?0:((page-1)*limit)+1; const end=Math.min(total,page*limit); document.getElementById('device-pagination-info').textContent = total ? `Menampilkan ${start}-${end} dari ${total} device` : 'Belum ada device'; document.getElementById('device-pagination').innerHTML = Array.from({ length: totalPages }, (_, idx) => { const p = idx + 1; return `<button type="button" class="btn btn-sm ${p === page ? 'btn-dark' : 'btn-outline-secondary'}" data-page="${p}">${p}</button>`; }).join(''); document.querySelectorAll('#device-pagination button').forEach((btn)=>btn.addEventListener('click',()=>{ deviceState.page=Number(btn.dataset.page||1); loadDevices(); })); }
  function syncControls(){ document.getElementById('device_q').value=deviceState.q; document.getElementById('device_outlet_id').value=String(deviceState.outlet_id||0); document.querySelectorAll('.device-status-tab').forEach((btn)=>btn.classList.toggle('active', btn.dataset.status===deviceState.status)); }
  function deviceQs(){ const p=new URLSearchParams(); p.set('device_q', deviceState.q); p.set('device_status', deviceState.status); p.set('device_outlet_id', deviceState.outlet_id); p.set('device_page', deviceState.page); p.set('device_limit', deviceState.limit); return p.toString(); }
  function openDevice(row = null) { deviceForm.reset(); deviceForm.elements.id.value = row?.id || ''; deviceForm.elements.device_code.value = row?.device_code || ''; deviceForm.elements.device_name.value = row?.device_name || ''; deviceForm.elements.outlet_id.value = row?.outlet_id || ''; deviceForm.elements.printer_role.value = row?.printer_role || 'CUSTOM'; deviceForm.elements.print_scope.value = row?.print_scope || 'DIVISION'; deviceForm.elements.connection_type.value = row?.connection_type || 'USB'; deviceForm.elements.agent_os.value = row?.agent_os || 'WINDOWS'; deviceForm.elements.agent_host.value = row?.agent_host || ''; deviceForm.elements.system_device_name.value = row?.system_device_name || ''; deviceForm.elements.mac_address.value = row?.mac_address || ''; deviceForm.elements.ip_address.value = row?.ip_address || ''; deviceForm.elements.port.value = row?.port || ''; deviceForm.elements.python_port.value = row?.python_port || ''; deviceForm.elements.paper_width_mm.value = String(row?.paper_width_mm || 80); deviceForm.elements.is_active.value = Number(row?.is_active ?? 1); document.getElementById('printerDeviceModalLabel').textContent = row ? `Edit Device: ${row.device_name}` : 'Tambah Device Printer'; deviceModal.show(); }
  async function loadDevices(){ syncControls(); const json = await getJson('<?= site_url('pos/printers/devices/data'); ?>?' + deviceQs()); const rows = json.rows || []; const body = document.getElementById('device-table-body'); const empty=document.getElementById('device-empty-state'); if(!rows.length){ body.innerHTML=''; empty.classList.remove('d-none'); } else { empty.classList.add('d-none'); body.innerHTML = rows.map((r)=>`<tr><td><div class="fw-semibold">${escapeHtml(r.device_name || '-')}</div><div class="small text-muted">${escapeHtml(r.device_code || '-')}</div></td><td>${escapeHtml(r.outlet_name || 'Global')}</td><td><div>${escapeHtml(r.printer_role || 'CUSTOM')}</div><div class="small text-muted">${escapeHtml(r.print_scope || 'DIVISION')}</div></td><td><div class="badge text-bg-light border">${escapeHtml(r.connection_type || 'USB')}</div><div class="small text-muted mt-1">${escapeHtml(r.system_device_name || r.ip_address || '-')}</div></td><td><div class="fw-semibold">${escapeHtml(r.agent_host || '-')}</div><div class="small text-muted">${escapeHtml(r.mac_address || '-')} ${r.python_port ? '| Port ' + escapeHtml(r.python_port) : ''}</div></td><td class="text-center">${statusBadge(r.is_active)}</td><td class="text-center"><div class="d-inline-flex gap-1 flex-wrap justify-content-center"><a class="btn btn-sm btn-outline-secondary" href="<?= site_url('pos/printers/preview'); ?>/${Number(r.id||0)}">Preview</a><button type="button" class="btn btn-sm btn-outline-success btn-device-test" data-id="${Number(r.id||0)}">Test</button><button type="button" class="btn btn-sm btn-outline-primary btn-device-edit" data-row="${rowPayload(r)}">Edit</button><button type="button" class="btn btn-sm ${Number(r.is_active||0)===1?'btn-outline-danger':'btn-outline-success'} btn-device-toggle" data-id="${Number(r.id||0)}">${Number(r.is_active||0)===1?'Nonaktifkan':'Aktifkan'}</button></div></td></tr>`).join(''); }
    pager(json.meta || {}); body.querySelectorAll('.btn-device-edit').forEach((btn)=>btn.addEventListener('click',()=>openDevice(parseRow(btn.dataset.row)))); body.querySelectorAll('.btn-device-test').forEach((btn)=>btn.addEventListener('click', async()=>{ const id = Number(btn.dataset.id || 0); if(!id)return; const originalText = btn.textContent; btn.disabled=true; btn.textContent='Testing...'; try { const json = await getJson('<?= site_url('pos/printers/test'); ?>/' + id); const payload = json.print_payload || {}; const printer = json.printer || {}; const pythonPort = Number(printer.python_port || 0); if (!pythonPort) throw new Error('Python port printer belum diisi. Lengkapi device printer dulu sebelum test print.'); const res = await fetch('http://127.0.0.1:' + pythonPort + '/cetak', { method:'POST', headers:{ 'Content-Type':'application/json' }, body: JSON.stringify({ text:String(payload.text || ''), printer_code:String(printer.device_code || ''), printer_name:String(printer.device_name || ''), paper_width_mm:Number(payload.paper_width_mm || 80), chars_per_line:Number(payload.chars_per_line || 48) }) }); if (!res.ok) throw new Error('HTTP ' + res.status); try { await res.json(); } catch (e) {} alert('Test print berhasil dikirim ke printer lokal.'); } catch (e) { alert(e && e.message ? e.message : 'Gagal test print printer lokal.'); } finally { btn.disabled=false; btn.textContent=originalText; } })); body.querySelectorAll('.btn-device-toggle').forEach((btn)=>btn.addEventListener('click', async()=>{ await postJson('<?= site_url('pos/printers/devices/toggle'); ?>/' + btn.dataset.id, {}); await loadDevices(); })); }
  document.getElementById('btn-new-device').addEventListener('click',()=>openDevice());
  document.querySelectorAll('.device-status-tab').forEach((btn)=>btn.addEventListener('click',()=>{ deviceState.status=btn.dataset.status; deviceState.page=1; loadDevices(); }));
  document.getElementById('device_q').addEventListener('input',(e)=>{ deviceState.q=e.target.value; deviceState.page=1; loadDevices(); });
  document.getElementById('device_outlet_id').addEventListener('change',(e)=>{ deviceState.outlet_id=Number(e.target.value || 0); deviceState.page=1; loadDevices(); });
  document.getElementById('btn-clear-device').addEventListener('click',()=>{ deviceState.q=''; deviceState.status='ACTIVE'; deviceState.outlet_id=0; deviceState.page=1; loadDevices(); });
  document.getElementById('btn-save-device').addEventListener('click', async()=>{ const payload = Object.fromEntries(new FormData(deviceForm).entries()); payload.port = payload.port === '' ? '' : Number(payload.port); payload.python_port = payload.python_port === '' ? '' : Number(payload.python_port); payload.paper_width_mm = Number(payload.paper_width_mm || 80); payload.is_active = Number(payload.is_active || 0); await postJson('<?= site_url('pos/printers/devices/save'); ?>', payload); deviceModal.hide(); await loadDevices(); });
  loadDevices().catch((e)=>alert(e.message));
});
</script>
